const topic = $.input.topic || '';
const query = 'YouTube Shorts viral ' + topic + ' trending ideas hooks';
return { query };

const topic = $.input.topic;
const results = $.steps.researchTrends.response.results || [];
let trends = '';
results.forEach((r, i) => { trends += (i + 1) + '. ' + (r.title || r.url) + ': ' + (r.text || '').slice(0, 150) + '
'; });

const prompt = 'You are an expert YouTube Shorts creator specializing in viral short-form content. Create a complete production package for a YouTube Short.

TOPIC: ' + topic + '

TRENDING RESEARCH:
' + trends + '

Return ONLY valid JSON:
{
  "title": "video title (under 60 chars)",
  "hook": "attention-grabbing first 2 seconds text",
  "script": {
    "voiceover": "complete voiceover script (30-60 seconds max)",
    "onScreenText": [{ "timestamp": "0-3s", "text": "bold text overlay" }]
  },
  "storyboard": [
    { "scene": 1, "timestamp": "0-5s", "visualDescription": "what appears on screen", "imagePrompt": "AI image generation prompt for this scene", "transition": "cut/zoom/slide" }
  ],
  "musicCue": { "genre": "music genre", "mood": "upbeat/dramatic/chill", "tempo": "BPM suggestion" },
  "thumbnailPrompt": "AI image prompt for the thumbnail",
  "hashtags": ["#shorts", "#viral"],
  "description": "YouTube description text",
  "estimatedDuration": "30-60s",
  "viralScore": "1-10 estimated viral potential"
}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'YouTube Short', script: { voiceover: raw }, storyboard: [] }; }

const ai = $.steps.parseAI.output;
let doc = 'YOUTUBE SHORTS PRODUCTION PACKAGE
';
doc += '=================================

';
doc += 'Title: ' + (ai.title || 'Untitled') + '
';
doc += 'Topic: ' + $.input.topic + '
';
doc += 'Duration: ' + (ai.estimatedDuration || '30-60s') + '
';
doc += 'Viral Score: ' + (ai.viralScore || 'N/A') + '/10
';
doc += 'Date: ' + new Date().toISOString().split('T')[0] + '

';
doc += 'HOOK: ' + (ai.hook || '') + '

';
doc += 'VOICEOVER SCRIPT
';
doc += '----------------
';
doc += ((ai.script && ai.script.voiceover) || '') + '

';
if (ai.script && ai.script.onScreenText) {
  doc += 'ON-SCREEN TEXT
';
  ai.script.onScreenText.forEach(t => { doc += '[' + t.timestamp + '] ' + t.text + '
'; });
  doc += '
';
}
doc += 'STORYBOARD
';
doc += '----------
';
if (ai.storyboard) { ai.storyboard.forEach(s => { doc += 'Scene ' + s.scene + ' [' + s.timestamp + ']: ' + s.visualDescription + '
  Image Prompt: ' + (s.imagePrompt || '') + '
  Transition: ' + (s.transition || '') + '

'; }); }
if (ai.musicCue) { doc += 'MUSIC: ' + ai.musicCue.genre + ' / ' + ai.musicCue.mood + ' / ' + (ai.musicCue.tempo || '') + '

'; }
doc += 'THUMBNAIL PROMPT: ' + (ai.thumbnailPrompt || '') + '
';
doc += 'HASHTAGS: ' + (ai.hashtags || []).join(' ') + '
';
doc += 'DESCRIPTION: ' + (ai.description || '') + '
';
return { doc, title: (ai.title || 'YT Short') + ' - Production Package' };
